1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return an empty result for an empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block unchanged (still life: survival)", () => {
15	    const sortCells = (cells: [number, number][]) =>
16	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
18	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
19	  });
20	  it("should kill a cell with more than three neighbors (overpopulation)", () => {
21	    const input: [number, number][] = [
22	      [0, 0], [1, 0], [2, 0],
23	      [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    expect(nextGeneration(input)).not.toContainEqual([1, 1]);
27	  });
28	  it("should bring a dead cell with exactly three neighbors to life (reproduction)", () => {
29	    const sortCells = (cells: [number, number][]) =>
30	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
31	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
32	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
33	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
34	  });
35	  it.todo("should transform a vertical blinker into a horizontal blinker, including negative coordinates");
36	});
