1	export type Cell = [number, number];
2	
3	const isNeighbor = (a: Cell, b: Cell): boolean => {
4	  const dx = Math.abs(a[0] - b[0]);
5	  const dy = Math.abs(a[1] - b[1]);
6	  return (dx !== 0 || dy !== 0) && dx <= 1 && dy <= 1;
7	};
8	
9	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
10	  cells.filter((other) => isNeighbor(cell, other)).length;
11	
12	const survives = (liveNeighbors: number): boolean =>
13	  liveNeighbors === 2 || liveNeighbors === 3;
14	
15	const key = (cell: Cell): string => `${cell[0]},${cell[1]}`;
16	
17	const neighborOffsets: Cell[] = [
18	  [-1, -1], [0, -1], [1, -1],
19	  [-1, 0], [1, 0],
20	  [-1, 1], [0, 1], [1, 1],
21	];
22	
23	const deadNeighborCandidates = (cells: Cell[]): Cell[] => {
24	  const live = new Set(cells.map(key));
25	  const candidates = cells.flatMap(([x, y]): Cell[] =>
26	    neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]),
27	  );
28	  const deadByKey = new Map<string, Cell>(
29	    candidates
30	      .filter((cell) => !live.has(key(cell)))
31	      .map((cell) => [key(cell), cell]),
32	  );
33	  return [...deadByKey.values()];
34	};
35	
36	export const nextGeneration = (cells: Cell[]): Cell[] => {
37	  const survivors = cells.filter((cell) =>
38	    survives(countLiveNeighbors(cell, cells)),
39	  );
40	  const born = deadNeighborCandidates(cells).filter(
41	    (cell) => countLiveNeighbors(cell, cells) === 3,
42	  );
43	  return [...survivors, ...born];
44	};
